import Foundation

enum Environment: String {
    case development = "dev"
    case staging = "stg"
    case production = "prod"
}

struct User {
    let name: String
    let email: String
}

class NetworkingManager {
    private let baseUrl: String
    private let session: URLSession

    init(environment: Environment) {
        self.baseUrl = "https://api.\(environment.rawValue).example.com"
        self.session = URLSession.shared
    }

    func getUser(completion: @escaping (User?, Error?) -> Void) {
        let url = URL(string: "\(baseUrl)/users/me")!

        session.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }

            let user = try! JSONDecoder().decode(User.self, from: data!)
            completion(user, nil)
        }.resume()
    }

    func authenticate(email: String, password: String, completion: @escaping (Bool, Error?) -> Void) {
        let url = URL(string: "\(baseUrl)/auth")!

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try! JSONEncoder().encode(["email": email, "password": password])

        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(false, error)
                return
            }

            completion(true, nil)
        }.resume()
    }
}